// Mostly GENERATED by scripts/generate_oscar_winners.py — do not edit the
// `kBestPictureWinners` list by hand. Source: Wikipedia 'Academy Award for
// Best Picture', resolved via TMDB search. Rerun annually after the next
// ceremony and re-commit.
//
// Non-Oscar award lists (Palme d'Or, BAFTA) are derived below as filters
// over `kBestPictureWinners` — they surface the subset of titles that won
// *both* the named award and Best Picture. Extending to comprehensive
// coverage (films that won Palme but not Best Picture, e.g. Shoplifters)
// requires a TMDB-backed generation pass; see `scripts/` for the Oscar
// pattern to follow.

/// Data class for a single award-winning title. Kept named `OscarWinner`
/// because the generator script emits the constant list with that
/// constructor — back-compat only. New code should prefer the `AwardWinner`
/// typedef below.
class OscarWinner {
  final int tmdbId;
  final String imdbId;
  final String title;
  final int year;
  final List<String> genres;
  final int runtime;
  final String posterPath;
  final String overview;

  const OscarWinner({
    required this.tmdbId,
    required this.imdbId,
    required this.title,
    required this.year,
    required this.genres,
    required this.runtime,
    required this.posterPath,
    required this.overview,
  });
}

typedef AwardWinner = OscarWinner;

/// Named sources we splice into the recommendation pool when the user
/// picks an award from the Awards dropdown on Home. Mapped to
/// `kAwardWinners` below. Keep this enum stable — it's persisted via its
/// name in `SharedPreferences` (`wn_awards_solo/_together`).
enum AwardCategory {
  /// Academy Award for Best Picture — ~97 films, full Wikipedia coverage.
  bestPicture,

  /// Cannes Palme d'Or — currently the intersection with Best Picture
  /// (Marty, The Lost Weekend, Parasite). Extend via script.
  palmeDor,

  /// BAFTA Best Film — currently the intersection with Best Picture.
  /// Extend via script.
  baftaBestFilm,
}

extension AwardCategoryLabel on AwardCategory {
  String get label => switch (this) {
        AwardCategory.bestPicture => 'Best Picture',
        AwardCategory.palmeDor => 'Palme d\'Or',
        AwardCategory.baftaBestFilm => 'BAFTA Best Film',
      };
}

/// Titles from `kBestPictureWinners` that also won the Cannes Palme d'Or.
/// Filtered at runtime (not a const) so we don't duplicate the data.
final List<AwardWinner> kPalmeDorWinners = kBestPictureWinners
    .where((w) => const {'Marty', 'The Lost Weekend', 'Parasite'}
        .contains(w.title))
    .toList(growable: false);

/// Titles from `kBestPictureWinners` that also won BAFTA Best Film.
/// Filtered at runtime. Doesn't include BAFTA-only winners (e.g. The
/// Pianist, Brokeback Mountain) — extending requires new TMDB lookups.
final List<AwardWinner> kBaftaBestFilmWinners = kBestPictureWinners
    .where((w) => const {
          'The Apartment',
          'Lawrence of Arabia',
          'Tom Jones',
          'A Man for All Seasons',
          'Midnight Cowboy',
          'The French Connection',
          'The Godfather',
          'Gandhi',
          'Amadeus',
          'The Last Emperor',
          'Schindler\'s List',
          'Forrest Gump',
          'Braveheart',
          'The English Patient',
          'American Beauty',
          'Gladiator',
          'Slumdog Millionaire',
          'The Hurt Locker',
          'The King\'s Speech',
          'The Artist',
          'Argo',
          '12 Years a Slave',
          'Nomadland',
          'Oppenheimer',
        }.contains(w.title))
    .toList(growable: false);

/// Lookup table for the service layer: given an `AwardCategory`, hand back
/// the list to splice into the candidate pool.
Map<AwardCategory, List<AwardWinner>> get kAwardWinners => {
      AwardCategory.bestPicture: kBestPictureWinners,
      AwardCategory.palmeDor: kPalmeDorWinners,
      AwardCategory.baftaBestFilm: kBaftaBestFilmWinners,
    };

